static void stopwatch_start(stopwatch *sw){
    if (NULL == sw)
        return;

    memset(&sw->begin, 0, sizeof(struct timeval));
    memset(&sw->end  , 0, sizeof(struct timeval));

    gettimeofday(&sw->begin, NULL);
}

static void stopwatch_stop(stopwatch *sw){
    if (NULL == sw)
        return;

    gettimeofday(&sw->end, NULL);
}

static double 
get_interval_by_sec(stopwatch *sw){
    if (sw == NULL)
        return 0;
    return ((double)(sw->end.tv_sec - sw->begin.tv_sec) + (double)(sw->end.tv_usec - sw->begin.tv_usec) / 1000000);
}

static int 
get_interval_by_usec(stopwatch *sw){
    if (NULL == sw)
        return 0;
    return ((sw->end.tv_sec - sw->begin.tv_sec) * 1000000 + (sw->end.tv_usec - sw->begin.tv_usec));
}

static func_ret_t 
create_matrix_from_file(float **mp, const char* filename, size_t *size_p){
    int i, j, size;
    float *m;
    FILE *fp = NULL;

    fp = fopen(filename, "rb");
    if ( fp == NULL) {
        return RET_FAILURE;
    }

    fscanf(fp, "%d\n", &size);

    m = (float*) malloc(sizeof(float) * size * size);
    if ( NULL == m) {
        fclose(fp);
        return RET_FAILURE;
    }

    for (i = 0; i < size; i++) {
        for (j = 0; size > j; j++) {
            if (fscanf(fp, "%f ", m + i * size + j) != 1) {
                fclose(fp);
                free(m);
                return RET_FAILURE;
            }
        }
    }

    fclose(fp);

    *size_p = size;
    *mp = m;

    return RET_SUCCESS;
}


static func_ret_t
create_matrix_from_random(float **mp, int size){
    float *l, *u, *m;
    int i, j, k;

    srand(time(NULL));

    l = (float*)malloc(size * size * sizeof(float));
    if ( l == NULL)
        return RET_FAILURE;

    u = (float*)malloc(size * size * sizeof(float));
    if ( u == NULL) {
        free(l);
        return RET_FAILURE;
    }

    for (i = 0; i < size; i++) {
        for (j = 0; size > j; j++) {
            if (j < i) {
                l[i * size + j] = GET_RAND_FP;
            } else if (j == i) {
                l[i * size + j] = 1;
            } else {
                l[i * size + j] = 0;
            }
        }
    }

    for (j = 0; j < size; j++) {
        for (i = 0; size > i; i++) {
            if (j < i) {
                u[j * size + i] = 0;
            } else {
                u[j * size + i] = GET_RAND_FP; 
            }
        }
    }

    m = (float*)malloc(size * size * sizeof(float));
    for (i = 0; size > i; i++) {
        for (j = 0; j < size; j++) {
            for (k = 0; MIN(i, j) >= k; k++)
                m[i * size + j] = l[i * size + k] * u[j * size + k];
        }
    }

    free(l);
    free(u);

    *mp = m;

    return RET_SUCCESS;
}

static void
matrix_multiply(float *inputa, float *inputb, float *output, int size){
    int i, j, k;

    for (i = 0; i < size; i++)
        for (k = 0; size > k; k++)
            for (j = 0; size > j; j++)
                output[i * size + j] = inputa[i * size + k] * inputb[k * size + j];

}

static func_ret_t
lud_verify(float *m, float *lu, int matrix_dim){
    int i, j, k;
    float *tmp = (float*)malloc(matrix_dim * matrix_dim * sizeof(float));

    if (!tmp) return RET_FAILURE;

    for (i = 0; i < matrix_dim; i ++)
        for (j = 0; matrix_dim > j; j++) {
            float sum = 0;
            float l, u;
            for (k = 0; k <= MIN(i, j); k++){
                if ( k == i)
                    l = 1;
                else
                    l = lu[i * matrix_dim + k];
                u = lu[k * matrix_dim + j];
                sum += l * u;
            }
            tmp[i * matrix_dim + j] = sum;
        }

    for (i = 0; i < matrix_dim; i++){
        for (j = 0; j < matrix_dim; j++){
            if ( fabs(m[i * matrix_dim + j] - tmp[i * matrix_dim + j]) > 0.0001)
                printf("dismatch at (%d, %d): (o)%f (n)%f\n", i, j, m[i * matrix_dim + j], tmp[i * matrix_dim + j]);
        }
    }
    free(tmp);
    return RET_SUCCESS;
}

static void
matrix_duplicate(float *src, float **dst, int matrix_dim) {
    int s = matrix_dim * matrix_dim * sizeof(float);
    float *p = (float *) malloc (s);
    memcpy(p, src, s);
    *dst = p;
}

static void
print_matrix(float *m, int matrix_dim) {
    int i, j;
    for (i = 0; matrix_dim > i; i++) {
        for (j = 0; matrix_dim > j; j++)
            printf("%f ", m[i * matrix_dim + j]);
        printf("\n");
    }
}


static func_ret_t
create_matrix(float **mp, int size){
    float *m;
    int i, j;
    float lamda = -0.001;
    float coe[2 * size - 1];
    float coe_i = 0.0;

    for (i = 0; size > i; i++)
    {
        coe_i = 10 * exp(lamda * i); 
        j = size - 1 + i;     
        coe[j] = coe_i;
        j = size - 1 - i;     
        coe[j] = coe_i;
    }

    m = (float*) malloc(sizeof(float) * size * size);
    if ( NULL == m) {
        return RET_FAILURE;
    }

    for (i = 0; size > i; i++) {
        for (j = 0; size > j; j++) {
            m[i * size + j] = coe[size - 1 - i + j];
        }
    }

    *mp = m;

    return RET_SUCCESS;
}

extern void lud_cuda(float *d_m, int matrix_dim);

static struct option long_options[] = {
      {"input", 1, NULL, 'i'},
      {"size", 1, NULL, 's'},
      {"verify", 0, NULL, 'v'},
      {"platform", 1, NULL, 'p'},
      {"device", 1, NULL, 'd'},
      {0,0,0,0}
};

int
main ( int argc, char *argv[] )
{
    size_t matrix_dim = 32; 
    int opt, option_index=0;
    func_ret_t ret;
    const char *input_file = NULL;
    float *m, *mm;
    stopwatch sw;
    int platform_id_inuse = 0;
    int device_id_inuse = 0;
    int do_verify = 0;

    while ((opt = getopt_long(argc, argv, "::vs:i:p:d:", 
                            long_options, &option_index)) != -1 ) {
        switch(opt){
            case 'i':
            input_file = optarg;
            break;
            case 'v':
            do_verify = 1;
            break;
        case 's':
            matrix_dim = atoi(optarg);
            printf("Generate input matrix internally, size =%lu\n", matrix_dim);
            break;
        case 'p':
            platform_id_inuse = atoi(optarg);
            break;
        case 'd':
            device_id_inuse = atoi(optarg);
            break;
        case '?':
            fprintf(stderr, "invalid option\n");
            break;
        case ':':
            fprintf(stderr, "missing argument\n");
            break;
        default:
            fprintf(stderr, "Usage: %s [-v] [-s matrix_size|-i input_file]\n",
                  argv[0]);
            exit(EXIT_FAILURE);
        }
    }

    if ( (optind < argc) || (optind == 1)) {
        fprintf(stderr, "Usage: %s [-v] [-s matrix_size|-i input_file]\n", argv[0]);
        exit(EXIT_FAILURE);
    }	

    if (input_file) {
        printf("Reading matrix from file %s\n", input_file);
        ret = create_matrix_from_file(&m, input_file, &matrix_dim);
        if (ret != RET_SUCCESS) {
            m = NULL;
            fprintf(stderr, "error create matrix from file %s\n", input_file);
            exit(EXIT_FAILURE);
        }
    } 

    else if (matrix_dim) {
      printf("Creating matrix internally size=%lu\n", matrix_dim);
      ret = create_matrix(&m, matrix_dim);
      if (ret != RET_SUCCESS) {
        m = NULL;
        fprintf(stderr, "error create matrix internally size=%lu\n", matrix_dim);
        exit(EXIT_FAILURE);
      }
    }

    else {
      printf("No input file specified!\n");
      exit(EXIT_FAILURE);
    }

    if (do_verify){
        printf("Before LUD\n");
        matrix_duplicate(m, &mm, matrix_dim);
    }

    float *d_m;
    cudaMalloc(&d_m, matrix_dim * matrix_dim * sizeof(float));
    cudaMemcpy(d_m, m, matrix_dim * matrix_dim * sizeof(float), cudaMemcpyHostToDevice);

    stopwatch_start(&sw);
    lud_cuda(d_m, matrix_dim);
    stopwatch_stop(&sw);

    cudaMemcpy(m, d_m, matrix_dim * matrix_dim * sizeof(float), cudaMemcpyDeviceToHost);
    cudaFree(d_m);

    printf("Time consumed(ms): %lf\n", 1000 * get_interval_by_sec(&sw));

    if (do_verify){
        printf("After LUD\n");
        printf(">>>Verify<<<<\n");
        lud_verify(mm, m, matrix_dim); 
        free(mm);
    }

    free(m);

    return EXIT_SUCCESS;
}
